import axios from 'axios';

// Create an axios instance with default configuration
const API = axios.create({
    baseURL: 'http://localhost:8080/api',  // Your Spring Boot API URL
    headers: {
        'Content-Type': 'application/json',
    }
});

// This is an "interceptor" - it runs before every request
// It automatically adds your JWT token to the Authorization header
API.interceptors.request.use(
    (config) => {
        // Get token from localStorage (where you saved it after login)
        const token = localStorage.getItem('token');

        // If token exists, add it to the request headers
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }

        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// This interceptor handles responses - if we get 401 (unauthorized),
// it means our token expired or is invalid
API.interceptors.response.use(
    (response) => {
        return response;
    },
    (error) => {
        if (error.response?.status === 401) {
            // Token expired or invalid - log out the user
            localStorage.removeItem('token');
            window.location.href = '/login';
        }
        return Promise.reject(error);
    }
);

export default API;
